using System;

// Nümayəndə təyini
public delegate void ButtonClickHandler(string message);

class Button
{
    // Hadisə təyini
    public event ButtonClickHandler OnClick;

    public void Click()
    {
        // Hadisəni işə salmaq
        OnClick?.Invoke("Düyməyə basıldı!");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Button button = new Button();

        // Hadisəyə abunə olma
        button.OnClick += ButtonClicked;

        // Düyməni basma simulyasiyası
        button.Click();
    }

    // Hadisə işləyicisi
    static void ButtonClicked(string message)
    {
        Console.WriteLine(message);
    }
}
// Output:
// Düyməyə basıldı!

using System;

public delegate void TemperatureChangeHandler(int newTemperature);

class Thermostat
{
    private int temperature;
    public event TemperatureChangeHandler OnTemperatureChange;

    public int Temperature
    {
        get => temperature;
        set
        {
            temperature = value;
            OnTemperatureChange?.Invoke(temperature);
        }
    }
}

class Program
{
    static void Main(string[] args)
    {
        Thermostat thermostat = new Thermostat();

        // Abunə olma
        thermostat.OnTemperatureChange += DisplayTemperature;

        // Temperaturu dəyişmək
        thermostat.Temperature = 25;

        // Abunəliyi ləğv etmək
        thermostat.OnTemperatureChange -= DisplayTemperature;

        // Bu dəyişiklik hadisəni işə salmayacaq
        thermostat.Temperature = 30;
    }

    static void DisplayTemperature(int temp)
    {
        Console.WriteLine($"Yeni temperatur: {temp}°C");
    }
}
// Output:
// Yeni temperatur: 25°C

