using System;

public delegate void ErrorHandler(string message);

class BadButton
{
    public event ErrorHandler OnClick;

    public void Click()
    {
        // Null yoxlaması yoxdur
        OnClick("Səhv baş verdi!"); // NullReferenceException riski
    }
}

class Program
{
    static void Main(string[] args)
    {
        BadButton button = new BadButton();
        try
        {
            button.Click();
        }
        catch (NullReferenceException ex)
        {
            Console.WriteLine("Səhv: Hadisəyə abunəçi yoxdur!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
